import { Tabs as TabsPrimitive, useTabs } from '@ark-ui/react/tabs';
import { clsx } from 'clsx';
import type { ComponentProps, ComponentRef } from 'react';
import { forwardRef } from 'react';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import styles from './Tabs.module.css';

type TabsVariant = 'default' | 'line';

const TabsRoot = forwardRef<
  ComponentRef<typeof TabsPrimitive.Root>,
  ComponentProps<typeof TabsPrimitive.Root> & { variant?: TabsVariant }
>(function TabsRoot({ className, variant = 'default', ...props }, ref) {
  return (
    <TabsPrimitive.Root
      ref={ref}
      data-slot="tabs-root"
      data-variant={variant}
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    />
  );
});

const TabsRootProvider = forwardRef<
  ComponentRef<typeof TabsPrimitive.RootProvider>,
  ComponentProps<typeof TabsPrimitive.RootProvider> & { variant?: TabsVariant }
>(function TabsRootProvider({ className, variant = 'default', ...props }, ref) {
  return (
    <TabsPrimitive.RootProvider
      ref={ref}
      data-slot="tabs-root-provider"
      data-variant={variant}
      className={clsx(styles.root, normalizeClassName(className))}
      {...props}
    />
  );
});

const TabsList = forwardRef<
  ComponentRef<typeof TabsPrimitive.List>,
  ComponentProps<typeof TabsPrimitive.List>
>(function TabsList({ className, ...props }, ref) {
  return (
    <TabsPrimitive.List
      ref={ref}
      data-slot="tabs-list"
      className={clsx(styles.list, normalizeClassName(className))}
      {...props}
    />
  );
});

const TabsTrigger = forwardRef<
  ComponentRef<typeof TabsPrimitive.Trigger>,
  ComponentProps<typeof TabsPrimitive.Trigger>
>(function TabsTrigger({ className, ...props }, ref) {
  return (
    <TabsPrimitive.Trigger
      ref={ref}
      data-slot="tabs-trigger"
      className={clsx(styles.trigger, normalizeClassName(className))}
      {...props}
    />
  );
});

const TabsIndicator = forwardRef<
  ComponentRef<typeof TabsPrimitive.Indicator>,
  ComponentProps<typeof TabsPrimitive.Indicator>
>(function TabsIndicator({ className, ...props }, ref) {
  return (
    <TabsPrimitive.Indicator
      ref={ref}
      data-slot="tabs-indicator"
      className={clsx(styles.indicator, normalizeClassName(className))}
      {...props}
    />
  );
});

const TabsContent = forwardRef<
  ComponentRef<typeof TabsPrimitive.Content>,
  ComponentProps<typeof TabsPrimitive.Content>
>(function TabsContent({ className, ...props }, ref) {
  return (
    <TabsPrimitive.Content
      ref={ref}
      data-slot="tabs-content"
      className={clsx(styles.content, normalizeClassName(className))}
      {...props}
    />
  );
});

const Tabs = Object.assign(TabsRoot, {
  Root: TabsRoot,
  RootProvider: TabsRootProvider,
  List: TabsList,
  Trigger: TabsTrigger,
  Indicator: TabsIndicator,
  Content: TabsContent,
  useTabs,
});

export { Tabs, useTabs };

@layer moduix.components {
  .root {
    box-sizing: border-box;
    display: flex;
    min-width: 0;
    flex-direction: column;
    gap: var(--moduix-tabs-gap, var(--moduix-spacing-3));
    color: var(--moduix-tabs-color, var(--moduix-color-foreground));

    &[data-orientation='vertical'] {
      flex-direction: row;
      align-items: stretch;
    }
  }

  .list {
    box-sizing: border-box;
    position: relative;
    z-index: 0;
    display: inline-flex;
    width: fit-content;
    max-width: 100%;
    align-items: stretch;
    gap: var(--moduix-tabs-list-gap, var(--moduix-spacing-1));
    padding: var(
        --moduix-tabs-list-padding-y,
        var(--moduix-tabs-list-padding, var(--moduix-spacing-1))
      )
      var(--moduix-tabs-list-padding-x, var(--moduix-tabs-list-padding, var(--moduix-spacing-1)));
    border: var(--moduix-tabs-list-border-width, var(--moduix-border-width-sm)) solid
      var(--moduix-tabs-list-border-color, var(--moduix-color-border));
    border-radius: var(--moduix-tabs-radius, var(--moduix-radius-lg));
    background-color: var(--moduix-tabs-list-bg, var(--moduix-color-muted));

    &[data-orientation='vertical'] {
      width: var(--moduix-tabs-vertical-list-width, 12rem);
      min-width: var(--moduix-tabs-vertical-list-width, 12rem);
      flex-direction: column;
    }

    .root[data-variant='line'] & {
      width: 100%;
      border-width: 0 0 var(--moduix-tabs-list-border-width, var(--moduix-border-width-sm));
      border-radius: 0;
      padding-inline: 0;
      background-color: transparent;
    }

    .root[data-orientation='vertical'][data-variant='line'] & {
      width: var(--moduix-tabs-vertical-list-width, 12rem);
      border-width: 0 var(--moduix-tabs-list-border-width, var(--moduix-border-width-sm)) 0 0;
    }
  }

  .trigger {
    box-sizing: border-box;
    position: relative;
    z-index: 1;
    display: inline-flex;
    align-items: center;
    justify-content: center;
    gap: var(--moduix-tabs-tab-content-gap, var(--moduix-spacing-2));
    height: var(--moduix-tabs-tab-height, var(--moduix-size-sm));
    margin: 0;
    appearance: none;
    border: 0;
    border-radius: var(--moduix-tabs-tab-radius, var(--moduix-radius-md));
    padding-inline: var(--moduix-tabs-tab-padding-x, var(--moduix-spacing-2-5));
    background: none;
    color: var(--moduix-tabs-tab-color, var(--moduix-color-muted-foreground));
    font: inherit;
    font-size: var(--moduix-tabs-tab-font-size, var(--moduix-text-sm));
    font-weight: var(--moduix-tabs-tab-font-weight, var(--moduix-weight-medium));
    line-height: var(--moduix-tabs-tab-line-height, var(--moduix-line-height-text-sm));
    text-decoration: none;
    user-select: none;
    white-space: nowrap;
    outline: 0;
    cursor: pointer;
    transition:
      color var(--moduix-tabs-tab-transition, var(--moduix-transition-default)),
      opacity var(--moduix-tabs-tab-transition, var(--moduix-transition-default));

    &[data-selected] {
      color: var(--moduix-tabs-tab-color-active, var(--moduix-color-foreground));
    }

    @media (hover: hover) {
      &:hover {
        color: var(
          --moduix-tabs-tab-color-hover,
          var(--moduix-tabs-tab-color-active, var(--moduix-color-foreground))
        );
      }
    }

    &:focus-visible {
      &::before {
        content: '';
        position: absolute;
        inset: 0;
        border-radius: inherit;
        outline: var(
            --moduix-tabs-focus-ring-width,
            var(--moduix-focus-ring-inset-width, var(--moduix-border-width-sm))
          )
          solid var(--moduix-tabs-focus-ring-color, var(--moduix-color-ring));
        outline-offset: var(--moduix-tabs-focus-ring-offset, 0);
      }
    }

    &[disabled],
    &[data-disabled] {
      cursor: default;
      opacity: var(--moduix-tabs-tab-disabled-opacity, var(--moduix-opacity-disabled));
      pointer-events: none;
    }

    & > svg {
      width: var(--moduix-tabs-tab-icon-size, var(--moduix-spacing-4));
      height: var(--moduix-tabs-tab-icon-size, var(--moduix-spacing-4));
      color: var(--moduix-tabs-tab-icon-color, currentColor);
      flex-shrink: 0;
    }
  }

  .indicator {
    position: absolute;
    z-index: 0;
    top: 50%;
    left: var(--left, 0);
    width: var(--width, 0);
    height: var(--moduix-tabs-indicator-size, var(--moduix-spacing-8));
    border-radius: var(--moduix-tabs-indicator-radius, var(--moduix-radius-md));
    background-color: var(--moduix-tabs-indicator-bg, var(--moduix-color-background));
    box-shadow: var(--moduix-tabs-indicator-shadow, var(--moduix-shadow-sm));
    translate: 0 -50%;
    transition:
      width var(--moduix-tabs-indicator-transition, var(--moduix-transition-default)),
      height var(--moduix-tabs-indicator-transition, var(--moduix-transition-default)),
      top var(--moduix-tabs-indicator-transition, var(--moduix-transition-default)),
      left var(--moduix-tabs-indicator-transition, var(--moduix-transition-default));

    .root[data-variant='line'] & {
      top: auto;
      bottom: 0;
      height: var(--moduix-tabs-line-indicator-size, var(--moduix-spacing-0-5));
      border-radius: var(--moduix-tabs-line-indicator-radius, var(--moduix-radius-full));
      background-color: var(
        --moduix-tabs-line-indicator-bg,
        var(--moduix-tabs-tab-color-active, var(--moduix-color-foreground))
      );
      translate: none;
      box-shadow: none;
      transition:
        width var(--moduix-tabs-line-indicator-transition, var(--moduix-transition-default)),
        height var(--moduix-tabs-line-indicator-transition, var(--moduix-transition-default)),
        top var(--moduix-tabs-line-indicator-transition, var(--moduix-transition-default)),
        left var(--moduix-tabs-line-indicator-transition, var(--moduix-transition-default));
    }

    &[data-orientation='vertical'] {
      top: var(--top, 0);
      left: 50%;
      width: calc(
        100% -
          (var(
              --moduix-tabs-list-padding-x,
              var(--moduix-tabs-list-padding, var(--moduix-spacing-1))
            ) *
            2)
      );
      height: var(--height, 0);
      translate: -50% 0;

      .root[data-variant='line'] & {
        bottom: auto;
        left: 0;
        width: var(--moduix-tabs-line-indicator-size, var(--moduix-spacing-0-5));
        translate: none;
      }
    }
  }

  .content {
    box-sizing: border-box;
    flex: 1;
    min-width: 0;
    margin: 0;
    border: var(--moduix-tabs-border-width, var(--moduix-border-width-sm)) solid
      var(--moduix-tabs-border-color, var(--moduix-color-border));
    border-radius: var(--moduix-tabs-radius, var(--moduix-radius-lg));
    background-color: var(--moduix-tabs-bg, var(--moduix-color-background));
    padding: var(--moduix-tabs-panel-padding, var(--moduix-spacing-4));
    color: var(--moduix-tabs-panel-color, var(--moduix-tabs-color, var(--moduix-color-foreground)));
    font-size: var(--moduix-tabs-panel-font-size, var(--moduix-text-sm));
    line-height: var(--moduix-tabs-panel-line-height, var(--moduix-line-height-text-sm));
    outline: 0;

    &:focus-visible {
      outline: var(
          --moduix-tabs-focus-ring-width,
          var(--moduix-focus-ring-inset-width, var(--moduix-border-width-sm))
        )
        solid var(--moduix-tabs-focus-ring-color, var(--moduix-color-ring));
      outline-offset: var(
        --moduix-tabs-panel-focus-ring-offset,
        var(--moduix-focus-ring-inset-offset)
      );
      border-radius: inherit;
    }

    &[hidden]:not([hidden='until-found']) {
      display: none;
    }
  }
}
